# Problem: Simulate Django ORM operations (filter, annotate, aggregate)
# on a list of dictionaries representing database rows.
#
# Approach:
# - filter_records: Parse kwargs for __gte/__lt suffixes to determine comparison type,
#   then keep only records matching ALL conditions (AND logic).
# - annotate_records: For each record, compute new fields based on (operation, field) tuples
#   and return copies with the new fields added.
# - aggregate: Extract values for each field, apply the aggregate operation, collect results.
#
# Time: O(n * k) for each function where n = records, k = number of kwargs
# Space: O(n) for returned lists/dicts
#
# Key steps:
# 1. filter: split kwarg keys on __gte/__lt, apply correct comparison
# 2. annotate: copy each record, apply "upper" or "double" transform
# 3. aggregate: collect field values, compute sum/avg/count/min/max

def filter_records(records: list[dict], **kwargs) -> list[dict]:
    # Implement Django-style filtering with support for __gte and __lt lookups
    conditions = []
    for key, value in kwargs.items():
        if key.endswith("__gte"):
            field = key[:-5]  # strip __gte suffix
            conditions.append((field, "gte", value))
        elif key.endswith("__lt"):
            field = key[:-4]  # strip __lt suffix
            conditions.append((field, "lt", value))
        else:
            conditions.append((key, "eq", value))

    result = []
    for record in records:
        # Record must satisfy ALL conditions (AND logic, like Django's filter)
        if all(_check(record, field, op, val) for field, op, val in conditions):
            result.append(record)
    return result


def _check(record, field, op, value):
    if op == "eq":
        return record[field] == value
    elif op == "gte":
        return record[field] >= value
    elif op == "lt":
        return record[field] < value
    return False


def annotate_records(records: list[dict], **kwargs) -> list[dict]:
    # Add computed fields to each record
    result = []
    for record in records:
        new_record = dict(record)  # shallow copy to avoid mutating original
        for new_field, (operation, source_field) in kwargs.items():
            if operation == "upper":
                new_record[new_field] = record[source_field].upper()
            elif operation == "double":
                new_record[new_field] = record[source_field] * 2
        result.append(new_record)
    return result


def aggregate(records: list[dict], **kwargs) -> dict:
    # Compute aggregate values (sum, avg, count, min, max)
    result = {}
    for result_name, (operation, field) in kwargs.items():
        # Extract non-None values for the target field
        values = [r[field] for r in records if r.get(field) is not None]

        if operation == "sum":
            result[result_name] = sum(values)
        elif operation == "avg":
            result[result_name] = sum(values) / len(values) if values else 0.0
        elif operation == "count":
            result[result_name] = len(values)
        elif operation == "min":
            result[result_name] = min(values)
        elif operation == "max":
            result[result_name] = max(values)
    return result
